prompt:
Write a JavaScript function `parseTemplate(template, data)` that supports:
- `{{variable}}` — variable substitution (supports dot notation like `{{user.name}}`)
- `{{#if condition}}...{{/if}}` — conditional blocks (condition is a key in data, truthy/falsy)
- `{{#each array}}...{{/each}}` — iteration (inside the block, `{{this}}` refers to current item, `{{this.prop}}` for objects)

Include this test code at the end:

const template = `Hello {{user.name}}!
{{#if showGreeting}}Welcome back!{{/if}}
{{#if showFarewell}}Goodbye!{{/if}}
Items:
{{#each items}}- {{this.name}}: \${{this.price}}
{{/each}}Total: {{total}}`;

const data = {
  user: { name: 'Alice' },
  showGreeting: true,
  showFarewell: false,
  items: [
    { name: 'Apple', price: 1.50 },
    { name: 'Banana', price: 0.75 }
  ],
  total: '$2.25'
};

console.log(parseTemplate(template, data));
